package com.cts.handson.service;import java.util.*;import org.springframework.stereotype.Service;import org.springframework.beans.factory.annotation.Autowired;import com.cts.handson.repository.CountryRepository;import com.cts.handson.entity.Country;@Service public class CountryService{@Autowired CountryRepository r;public Country get(String c){return r.findByCode(c);}public List<Country> contains(String s){return r.findByNameContaining(s);}public List<Country> starts(String s){return r.findByNameStartingWith(s);}}